SELECT

FROM property p
WHERE p.id = #{propertyId}

SELECT
  *
FROM (
  SELECT

  FROM property p
) candidate


    AND (

        candidate.sgg_nm = #{region}
        OR CONCAT(candidate.sgg_nm, ' ', candidate.umd_nm) = #{region}

    )


    AND candidate.latest_sale_price > 0
    AND candidate.latest_sale_price <= #{filter.salePriceMax}




        AND candidate.latest_monthly_rent_deposit > 0
        AND candidate.latest_monthly_rent_deposit <= #{filter.depositMax}


        AND candidate.latest_deposit > 0
        AND candidate.latest_deposit <= #{filter.depositMax}




    AND candidate.latest_monthly_rent_amount > 0
    AND candidate.latest_monthly_rent_amount <= #{filter.monthlyRentMax}


    AND candidate.exclusive_area >= #{filter.minExclusiveArea}
